module top_module(
        gin, 
        bout
);parameter width = 6;

input  [width-1 : 0] gin;
output [width-1 : 0] bout;

reg    [width-1 : 0] gray_reg;
integer i;
assign bout = gray_reg;

always @(gin)
begin
    gray_reg[width-1] = gin[width-1];
    if (width > 1)
    begin
        for (i=width-2; i >= 0; i=i-1)
            gray_reg[i] = gray_reg[i+1] ^ gin[i];
    end
end

endmodule
